import java.util.*;

class Solution {
    public List<String> makeableRecipes(String[] recipes, String[][] ingredients, String[] supplies) {
        Map<String, Set<String>> dependentRecipes = new HashMap<>();
        Set<String> availableSupplies = new HashSet<>(Arrays.asList(supplies));
        for (int i = 0; i < recipes.length; i++) {
            dependentRecipes.put(recipes[i], new HashSet<>(Arrays.asList(ingredients[i])));
        }

        Queue<String> q = new LinkedList<>();
        for (String supply : availableSupplies) {
            q.offer(supply);
        }

        while (!q.isEmpty()) {
            String currentItem = q.poll();
            for (Map.Entry<String, Set<String>> recipe : dependentRecipes.entrySet()) {
                if (recipe.getValue().contains(currentItem)) {
                    recipe.getValue().remove(currentItem);
                    if (recipe.getValue().isEmpty()) {
                        availableSupplies.add(recipe.getKey());
                        q.offer(recipe.getKey());
                    }
                }
            }
        }

